    "Authorization": "Bearer Bearer {YOUR_ACCESS_TOKEN}",
    "X-Organization-Id": "1",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "name": "Công ty A",
    "slug": "cong-ty-a",
