    "search": "architecto",
    "status": "active",
    "from_date": "2026-01-01",
    "to_date": "2026-12-31",
    "sort_by": "name",
    "sort_order": "asc",
    "limit": "10",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "X-Organization-Id": "1",
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>


