</p>



<span id="example-requests-PATCHapi-issuing-levels-bulk-status">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PATCH \
    "http://localhost/api/issuing-levels/bulk-status" \
    --header "Authorization: Bearer Bearer {YOUR_ACCESS_TOKEN}" \
    --header "X-Organization-Id: 1" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"ids\": [
        1,
        2,
        3
    ],
    \"status\": \"inactive\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/issuing-levels/bulk-status"
);

const headers = {
    "Authorization": "Bearer Bearer {YOUR_ACCESS_TOKEN}",
    "X-Organization-Id": "1",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "ids": [
        1,
        2,
        3
    ],
    "status": "inactive"
};

fetch(url, {
    method: "PATCH",
