                    <h2 id="document-linh-vuc-GETapi-document-fields-export">Xuất Excel lĩnh vực</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Xuất ra các trường: id, name, description, status, created_by, updated_by, created_at, updated_at.</p>

<span id="example-requests-GETapi-document-fields-export">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost/api/document-fields/export?search=architecto&amp;status=architecto&amp;from_date=2026-01-01&amp;to_date=2026-12-31&amp;sort_by=created_at&amp;sort_order=desc&amp;limit=10" \
    --header "Authorization: Bearer Bearer {YOUR_ACCESS_TOKEN}" \
    --header "X-Organization-Id: 1" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/document-fields/export"
);

const params = {
    "search": "architecto",
    "status": "architecto",
    "from_date": "2026-01-01",
    "to_date": "2026-12-31",
    "sort_by": "created_at",
    "sort_order": "desc",
    "limit": "10",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer Bearer {YOUR_ACCESS_TOKEN}",
    "X-Organization-Id": "1",
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>


