<span id="example-requests-POSTapi-meetings--meeting_id--speech-requests">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost/api/meetings/1/speech-requests" \
    --header "Authorization: Bearer Bearer {YOUR_ACCESS_TOKEN}" \
    --header "X-Organization-Id: 1" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"meeting_agenda_id\": 1,
    \"content\": \"architecto\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/meetings/1/speech-requests"
);

const headers = {
    "Authorization": "Bearer Bearer {YOUR_ACCESS_TOKEN}",
    "X-Organization-Id": "1",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "meeting_agenda_id": 1,
    "content": "architecto"
};

fetch(url, {
    method: "POST",
